function useDebouncedCallback<F extends (...args: any[]) => any>(fn: F, ms: number): F & { cancel(): void; flush(): void } {
  const timer = useRef<ReturnType<typeof setTimeout>>();
  const fnRef = useRef(fn);
  const lastArgs = useRef<unknown[]>([]);
  useEffect(() => { fnRef.current = fn; }, [fn]);

  const debounced = useCallback((...args: Parameters<F>) => {
    lastArgs.current = args;
    if (timer.current) clearTimeout(timer.current);
    timer.current = setTimeout(() => fnRef.current(...lastArgs.current), ms);
  }, [ms]) as F & { cancel(): void; flush(): void };

  debounced.cancel = () => { if (timer.current) clearTimeout(timer.current); };
  debounced.flush = () => { if (timer.current) { clearTimeout(timer.current); fnRef.current(...lastArgs.current); } };
  return debounced;
}

