// Composable hook factory with debounce + throttle + leading/trailing/max-wait
import { useRef, useEffect, useCallback } from 'react';

export interface DebounceOptions { leading?: boolean; trailing?: boolean; maxWait?: number; }

export function useDebouncedFn<F extends (...args: any[]) => any>(fn: F, wait: number, options: DebounceOptions = {}) {
  const { leading = false, trailing = true, maxWait } = options;
  const fnRef = useRef(fn);
  const timerId = useRef<ReturnType<typeof setTimeout>>();
  const maxTimerId = useRef<ReturnType<typeof setTimeout>>();
  const lastCallTime = useRef<number>(0);
  const lastInvokeTime = useRef<number>(0);
  const lastArgs = useRef<Parameters<F>>();

  useEffect(() => { fnRef.current = fn; }, [fn]);

  const invoke = useCallback(() => {
    if (lastArgs.current) {
      fnRef.current(...lastArgs.current);
      lastInvokeTime.current = Date.now();
    }
  }, []);

  const cancel = useCallback(() => {
    if (timerId.current) clearTimeout(timerId.current);
    if (maxTimerId.current) clearTimeout(maxTimerId.current);
  }, []);

  const flush = useCallback(() => {
    cancel();
    invoke();
  }, [cancel, invoke]);

  const debounced = useCallback((...args: Parameters<F>) => {
    const now = Date.now();
    const isInvoking = leading && now - lastInvokeTime.current >= wait;
    lastArgs.current = args;
    lastCallTime.current = now;
    cancel();

    if (isInvoking) invoke();
    else if (trailing) timerId.current = setTimeout(invoke, wait);

    if (maxWait !== undefined && !maxTimerId.current) {
      maxTimerId.current = setTimeout(() => { invoke(); maxTimerId.current = undefined; }, maxWait);
    }
  }, [wait, leading, trailing, maxWait, invoke, cancel]);

  return Object.assign(debounced, { cancel, flush });
}

