interface DynamicCommand {
  id: string;
  label: string;
  description?: string;
  group?: string;
  shortcut?: string[];
  run(): void | Promise<void>;
  context?: string;  // when to show
}

export function useCommandPalette() {
  const [commands, setCommands] = useState<DynamicCommand[]>([]);
  const [loaders, setLoaders] = useState<Array<(q: string) => Promise<DynamicCommand[]>>>([]);

  const register = useCallback((cmds: DynamicCommand[]) => {
    setCommands(c => [...c, ...cmds]);
    return () => setCommands(c => c.filter(x => !cmds.some(y => y.id === x.id)));
  }, []);

  const registerLoader = useCallback((loader: (q: string) => Promise<DynamicCommand[]>) => {
    setLoaders(l => [...l, loader]);
    return () => setLoaders(l => l.filter(x => x !== loader));
  }, []);

  return { register, registerLoader, commands, loaders };
}

