// Headless useDropzone hook
function useDropzone({ accept, maxSize, multiple = true }: DropzoneOptions) {
  const [state, setState] = useState<{ over: boolean; errors: string[] }>({ over: false, errors: [] });
  const inputRef = useRef<HTMLInputElement>(null);

  const validate = (files: File[]) => {
    const errs: string[] = [];
    const valid: File[] = [];
    files.forEach(f => {
      if (accept && !accept.test(f.type)) errs.push(`${f.name}: invalid type`);
      else if (maxSize && f.size > maxSize) errs.push(`${f.name}: too large`);
      else valid.push(f);
    });
    setState(s => ({ ...s, errors: errs }));
    return valid;
  };

  const getRootProps = () => ({
    onDragOver: (e: React.DragEvent) => { e.preventDefault(); setState(s => ({ ...s, over: true })); },
    onDragLeave: () => setState(s => ({ ...s, over: false })),
    onDrop: (e: React.DragEvent) => {
      e.preventDefault();
      setState(s => ({ ...s, over: false }));
      return validate(Array.from(e.dataTransfer.files));
    },
    onClick: () => inputRef.current?.click(),
    onKeyDown: (e: React.KeyboardEvent) => { if (e.key === 'Enter' || e.key === ' ') inputRef.current?.click(); },
    role: 'button' as const,
    tabIndex: 0,
    'aria-label': 'Drop files or click to browse'
  });

  const getInputProps = () => ({
    ref: inputRef,
    type: 'file' as const,
    accept: accept?.source,
    multiple,
    hidden: true,
    onChange: (e: React.ChangeEvent<HTMLInputElement>) => validate(Array.from(e.target.files ?? []))
  });

  return { getRootProps, getInputProps, isDragActive: state.over, errors: state.errors };
}

