// Event sourcing + ordering + delivery guarantee
class NotificationStream {
  private lastEventId = 0;
  private buffer = new Map<number, NotificationEvent>();
  private subscribers = new Set<(events: NotificationEvent[]) => void>();

  constructor(private endpoint: string) {}

  start() {
    // SSE with resume from lastEventId
    const es = new EventSource(`${this.endpoint}?lastEventId=${this.lastEventId}`);
    es.onmessage = (e) => {
      const event: NotificationEvent = JSON.parse(e.data);
      this.buffer.set(event.id, event);
      this.flushOrdered();
    };
  }

  private flushOrdered() {
    // Emit in order, fill gaps from server
    while (this.buffer.has(this.lastEventId + 1)) {
      const event = this.buffer.get(this.lastEventId + 1)!;
      this.subscribers.forEach(s => s([event]));
      this.buffer.delete(this.lastEventId + 1);
      this.lastEventId++;
    }
    // If gap, request missing from server
    if (this.buffer.size > 0 && Math.min(...this.buffer.keys()) > this.lastEventId + 1) {
      this.fetchMissing();
    }
  }

  private async fetchMissing() {
    // Request via REST endpoint
  }

  subscribe(fn: (events: NotificationEvent[]) => void) {
    this.subscribers.add(fn);
    return () => this.subscribers.delete(fn);
  }
}

