// Router-level prefetch with priority + budget
class PrefetchManager {
  private queue: Array<{ priority: number; fn: () => Promise<void> }> = [];
  private active = 0;
  private maxConcurrent = 3;

  schedule(priority: 'high' | 'normal' | 'low', fn: () => Promise<void>) {
    if ((navigator as any).connection?.saveData) return;
    if ((navigator as any).connection?.effectiveType === 'slow-2g') return;
    this.queue.push({ priority: { high: 0, normal: 1, low: 2 }[priority], fn });
    this.queue.sort((a, b) => a.priority - b.priority);
    this.drain();
  }

  private async drain() {
    while (this.queue.length > 0 && this.active < this.maxConcurrent) {
      const item = this.queue.shift()!;
      this.active++;
      try { await item.fn(); } catch {} finally { this.active--; this.drain(); }
    }
  }
}

