// Hover intent: only triggers after delay; cancels if mouse leaves quickly
function useHoverIntent<T extends HTMLElement = HTMLElement>(options: { enterDelay?: number; leaveDelay?: number } = {}) {
  const { enterDelay = 100, leaveDelay = 100 } = options;
  const [active, setActive] = useState(false);
  const ref = useRef<T>(null);
  const enterTimer = useRef<ReturnType<typeof setTimeout>>();
  const leaveTimer = useRef<ReturnType<typeof setTimeout>>();

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    const enter = () => {
      if (leaveTimer.current) clearTimeout(leaveTimer.current);
      enterTimer.current = setTimeout(() => setActive(true), enterDelay);
    };
    const leave = () => {
      if (enterTimer.current) clearTimeout(enterTimer.current);
      leaveTimer.current = setTimeout(() => setActive(false), leaveDelay);
    };

    el.addEventListener('pointerenter', enter);
    el.addEventListener('pointerleave', leave);
    return () => {
      el.removeEventListener('pointerenter', enter);
      el.removeEventListener('pointerleave', leave);
      if (enterTimer.current) clearTimeout(enterTimer.current);
      if (leaveTimer.current) clearTimeout(leaveTimer.current);
    };
  }, [enterDelay, leaveDelay]);

  return [ref, active] as const;
}

