function TreeView({ rootId }: Props) {
  const queryClient = useQueryClient();
  const { data: tree } = useQuery({ queryKey: ['tree', rootId], queryFn: () => fetchTree(rootId) });

  const moveMutation = useMutation({
    mutationFn: ({ id, parentId, index }: MoveArgs) => fetch(`/api/nodes/${id}/move`, { method: 'POST', body: JSON.stringify({ parentId, index }) }),
    onMutate: async (move) => {
      await queryClient.cancelQueries({ queryKey: ['tree', rootId] });
      const previous = queryClient.getQueryData(['tree', rootId]);
      queryClient.setQueryData(['tree', rootId], (old: Tree) => applyMove(old, move));
      return { previous };
    },
    onError: (_e, _v, ctx) => ctx?.previous && queryClient.setQueryData(['tree', rootId], ctx.previous)
  });

  return (
    <Tree data={tree} onMove={({ dragIds, parentId, index }) => moveMutation.mutate({ id: dragIds[0], parentId, index })}>
      {Node}
    </Tree>
  );
}

