// Reconnect + ordering
class NotificationConnection {
  private ws: WebSocket | null = null;
  private reconnectAttempts = 0;
  private lastEventId: string | null = null;

  connect(onMessage: (n: Notification) => void) {
    this.ws = new WebSocket(`wss://api/notifications?since=${this.lastEventId ?? ''}`);
    this.ws.onmessage = (e) => {
      const n = JSON.parse(e.data);
      this.lastEventId = n.id;
      onMessage(n);
    };
    this.ws.onclose = () => this.reconnect(onMessage);
  }

  private reconnect(onMessage: any) {
    const delay = Math.min(30000, 1000 * 2 ** this.reconnectAttempts);
    setTimeout(() => this.connect(onMessage), delay);
    this.reconnectAttempts++;
  }
}

