export function useNotificationCenter() {
  const queryClient = useQueryClient();
  const { data, fetchNextPage, hasNextPage } = useInfiniteQuery({
    queryKey: ['notifications'],
    queryFn: ({ pageParam }) => fetch(`/api/notifications?cursor=${pageParam ?? ''}`).then(r => r.json()),
    initialPageParam: null,
    getNextPageParam: (last) => last.nextCursor
  });

  const markRead = useMutation({
    mutationFn: (ids: string[]) => fetch('/api/notifications/read', { method: 'POST', body: JSON.stringify({ ids }) }),
    onMutate: async (ids) => {
      await queryClient.cancelQueries({ queryKey: ['notifications'] });
      queryClient.setQueryData(['notifications'], (old: any) => ({
        ...old,
        pages: old.pages.map((p: any) => ({ ...p, items: p.items.map((n: any) => ids.includes(n.id) ? { ...n, read: true } : n) }))
      }));
    }
  });

  const items = data?.pages.flatMap(p => p.items) ?? [];
  const unread = items.filter(n => !n.read).length;

  return {
    items, unread,
    markRead: markRead.mutate,
    markAllRead: () => markRead.mutate(items.filter(n => !n.read).map(n => n.id)),
    loadMore: fetchNextPage,
    hasMore: hasNextPage
  };
}

